_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // feather pen
    ret = max(ret, texture( sampler_main, (vUv-0.5)*(1-8*length(uTexSize.zw)) + 0.5 ).xyz);
    ret = max(ret, texture( sampler_main, (vUv-0.5)*(1+8*length(uTexSize.zw)) + 0.5 ).xyz);

    // darken over uTime
    ret -= 0.024;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


// This is the tower and star section, composite shader mod edited
vec2 uv6 = (vUv-.5)*uAspect.xy ;
float rad4 = 6*length(uv6);
float rad3 = 1/(rad4+.1);

uv5 = vec2 (vAngle*0.10, rad3*2);
rs3 = uv5;
uv5.y = uv5.y + q31;
////////////////
vec2 uv1 = (vUv-.5)*uAspect.xy ;
float rad2 = 6*length(uv1);
float rad1 = 3/(rad2+.1);

uv2 = vec2 (vAngle*1.15, rad1*2);
rs2 = uv2;
uv2.y = uv2.y + q30;
// End to edited

    ret = texture(sampler_main, vUv).xyz;
    //ret = max( ret, texture(sampler_main, 1-vUv).zyx );

    float L = lum(ret);
    float use_tex = 0.75 - clamp01(L*10-1);

    vec3 tex= texture(sampler_kmj_blue_black,vUv).xyz;

    tex*= tex;
      // shadow:
      float L2 = lum(GetBlur2(vUv - 0.01));

    ret = mix(ret, tex, use_tex);

// STARS
float uv_stars = texture( sampler_space_stars, uv5);
if (uv_stars > .2)
   { ret = texture( sampler_space_stars, uv5); }
// END //

// TOWER
float uv_tower = texture( sampler_spacetower01, uv2);
if (uv_tower > .2)
   { ret = texture( sampler_spacetower01, uv2)*(audioLowSmooth*0.3); }
// END //

    ret *= 1.00; //gamma

// Thank you for edited by Jian Simanjuntak //

  fragColor = ret;
}
